import type GeoJSON from 'geojson';
import type { BehaviorTrackingProps } from '@dynatrace/strato-components/core';
import type { LegendColorLayerProps } from './coloring.js';
import type { Location } from './location.js';
/**
 * Data type for connections in the Connection Layer.
 * @typeParam L - Object extending Location.
 * @public
 */
export type Connection = {
    /** Array of connections */
    path: Location[];
};
/**
 * The ConnectionLayer props
 * @typeParam T - Object extending Connection
 * @public
 */
export type ConnectionLayerProps<T extends Connection> = ConnectionLayerBaseProps<T> & (ConnectionColorProps<T> | LegendColorLayerProps);
/**
 * Shape of the Connection Layer Component Props.
 * @typeParam T - Object extending Connection<L>.
 * @public
 */
export interface ConnectionLayerBaseProps<T extends Connection> extends BehaviorTrackingProps {
    /** Set of data related to the connections */
    data: T[];
    /**
     * Specifies the line type.
     * @defaultValue 'solid'
     */
    line?: 'dashed' | 'solid';
    /**
     * Position of the arrows in relation of the connection direction
     */
    directionIndicator?: 'start' | 'end' | 'both';
    /**
     * Declare whether the curve is linear or smooth
     * @defaultValue 'linear'
     */
    curve?: CurvedLine;
    /**
     * Specifies the thickness of the connection path.
     * It can accept numbers from 1 to 64 (included).
     * @defaultValue 2
     */
    thickness?: number;
}
/** @internal */
export type InternalConnectionLayerProps<T extends Connection> = ConnectionLayerProps<T> & {
    layerId: string;
};
/** @internal */
export interface FeatureProperties {
    id: string;
    __lineColor: string;
    __lineHoveredColor: string;
    __lineWidth: number;
    __angle?: number;
    curve?: CurvedLine;
    path: Location[];
}
export type GeoJSONFeature<T extends GeoJSON.Geometry> = GeoJSON.Feature<T, FeatureProperties>;
/**
 * This property is responsible for setting the curve type
 * @defaultValue linear
 * @public
 */
export type CurvedLine = 'linear' | 'smooth';
/**
 * Props to configure a connection Layer with custom coloring
 * @typeParam T - Object extending Connection
 * @public
 */
export interface ConnectionColorProps<T extends Connection> {
    /**
     * Specifies the color of the connection layer.
     * @defaultValue Colors.Charts.Categorical.Color03.Default
     */
    color?: string | ((connection: T) => string);
}
/** @internal */
export type ConnectionTooltipStatePayload = {
    path: Location[];
    __lineColor: string;
    __lineWidth: number;
    __nullValues: string[] | undefined;
};
